AA,CACA,eAAA,CACA,iBAAA,CACA,mBAAA,CACA,UAAA","sourcesContent":["\n.imap-renderer {\n  width: 100%;\n  height: 100%;\n  overflow: hidden;\n  position: relative;\n  background: #111114;\n  cursor: grab;\n  user-select: none;\n\n  &.dragging {\n    cursor: grabbing;\n  }\n}\n\n.imap-canvas {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  transform-origin: 0 0;\n  transition: none;\n}\n\n.imap-bg {\n  width: 100%;\n  height: 100%;\n  object-fit: contain;\n  display: block;\n  opacity: 0;\n  transition: opacity 0.3s ease;\n\n  &.visible {\n    opacity: 1;\n  }\n}\n\n.imap-pin {\n  position: absolute;\n  transform: translate(-50%, -100%);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  cursor: pointer;\n  z-index: 10;\n  transition: transform 0.15s ease;\n\n  &:hover {\n    transform: translate(-50%, -100%) scale(1.15);\n    z-index: 20;\n\n    .imap-pin-label {\n      opacity: 1;\n      transform: translateY(0);\n    }\n  }\n}\n\n.imap-pin-icon {\n  font-size: 22px;\n  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.6));\n  position: relative;\n  z-index: 2;\n}\n\n.imap-pin-label {\n  margin-top: 2px;\n  font-size: 11px;\n  color: #fff;\n  background: rgba(0, 0, 0, 0.75);\n  padding: 2px 6px;\n  border-radius: 4px;\n  white-space: nowrap;\n  max-width: 120px;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  opacity: 0.7;\n  transform: translateY(-2px);\n  transition: all 0.2s ease;\n  border: 1px solid var(--pin-color, #e74c3c);\n}\n\n.imap-pin-pulse {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  width: 12px;\n  height: 12px;\n  border-radius: 50%;\n  background: var(--pin-color, #e74c3c);\n  opacity: 0.4;\n  transform: translate(-50%, -50%);\n  animation: pulse 2s ease-in-out infinite;\n}\n\n@keyframes pulse {\n\n  0%,\n  100% {\n    transform: translate(-50%, -50%) scale(1);\n    opacity: 0.4;\n  }\n\n  50% {\n    transform: translate(-50%, -50%) scale(2);\n    opacity: 0;\n  }\n}\n\n.imap-loading {\n  position: absolute;\n  inset: 0;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: 12px;\n  color: rgba(255, 255, 255, 0.4);\n  font-size: 14px;\n  z-index: 30;\n}\n\n.imap-spinner {\n  width: 28px;\n  height: 28px;\n  border: 3px solid rgba(179, 139, 89, 0.2);\n  border-top-color: #b38b59;\n  border-radius: 50%;\n  animation: spin 0.8s linear infinite;\n}\n\n@keyframes spin {\n  to {\n    transform: rotate(360deg);\n  }\n}\n\n.imap-error {\n  position: absolute;\n  inset: 0;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: 8px;\n  color: #e57373;\n  font-size: 14px;\n  z-index: 30;\n}\n\n.imap-error-url {\n  font-size: 11px;\n  color: rgba(255, 255, 255, 0.25);\n  max-width: 80%;\n  word-break: break-all;\n  text-align: center;\n}\n\n.imap-zoom-indicator {\n  position: absolute;\n  bottom: 8px;\n  right: 8px;\n  font-size: 11px;\n  color: rgba(255, 255, 255, 0.3);\n  background: rgba(0, 0, 0, 0.4);\n  padding: 2px 6px;\n  border-radius: 4px;\n  pointer-events: none;\n  z-index: 25;\n}\n"],"sourceRoot":""}]);
