r: #fff;\n  }\n}\n\n.imap-travel-close {\n  background: none;\n  border: none;\n  color: rgba(255, 255, 255, 0.4);\n  font-size: 16px;\n  cursor: pointer;\n  padding: 4px;\n  border-radius: 50%;\n  transition: all 0.2s;\n\n  &:hover {\n    color: #fff;\n    background: rgba(255, 255, 255, 0.1);\n  }\n}\n\n.imap-travel-body {\n  padding: 16px;\n  overflow-y: auto;\n}\n\n.imap-travel-dest {\n  font-size: 14px;\n  color: rgba(255, 255, 255, 0.65);\n  margin-bottom: 12px;\n\n  strong {\n    color: #b38b59;\n  }\n}\n\n.imap-travel-label {\n  font-size: 14px;\n  color: rgba(255, 255, 255, 0.5);\n  margin: 0 0 10px;\n}\n\n.imap-travel-field {\n  margin-bottom: 12px;\n}\n\n.imap-input {\n  width: 100%;\n  padding: 8px 12px;\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 6px;\n  color: #fff;\n  font-size: 14px;\n  outline: none;\n  transition: border-color 0.2s;\n  box-sizing: border-box;\n\n  &:focus {\n    border-color: rgba(179, 139, 89, 0.5);\n  }\n\n  &::placeholder {\n    color: rgba(255, 255, 255, 0.25);\n  }\n}\n\n.imap-checkbox-label {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  cursor: pointer;\n  font-size: 14px;\n  color: rgba(255, 255, 255, 0.7);\n\n  input[type='checkbox'] {\n    accent-color: #b38b59;\n  }\n}\n\n.imap-travel-actions {\n  display: flex;\n  gap: 8px;\n  justify-content: center;\n  margin-top: 4px;\n}\n\n.imap-activity-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 6px;\n  margin-bottom: 12px;\n}\n\n.imap-activity-btn {\n  padding: 8px 4px;\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  border-radius: 6px;\n  color: rgba(255, 255, 255, 0.75);\n  font-size: 13px;\n  cursor: pointer;\n  transition: all 0.15s;\n\n  &:hover {\n    background: rgba(179, 139, 89, 0.15);\n    border-color: rgba(179, 139, 89, 0.3);\n    color: #c9a96a;\n  }\n}\n\n.imap-travel-custom {\n  display: flex;\n  gap: 6px;\n  align-items: center;\n  padding-top: 8px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n\n  .imap-input {\n    flex: 1;\n  }\n}\n\n.imap-btn {\n  padding: 8px 16px;\n  border-radius: 6px;\n  font-size: 13px;\n  cursor: pointer;\n  transition: all 0.2s;\n  border: none;\n  white-space: nowrap;\n\n  &:disabled {\n    opacity: 0.4;\n    cursor: not-allowed;\n  }\n}\n\n.imap-btn-primary {\n  background: linear-gradient(135deg, #b38b59, #9a7548);\n  color: #fff;\n\n  &:hover:not(:disabled) {\n    background: linear-gradient(135deg, #c99e68, #b38b59);\n  }\n}\n\n.imap-btn-secondary {\n  background: rgba(255, 255, 255, 0.08);\n  color: rgba(255, 255, 255, 0.75);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n\n  &:hover {\n    background: rgba(255, 255, 255, 0.12);\n  }\n}\n\n.imap-btn-ghost {\n  background: none;\n  color: rgba(255, 255, 255, 0.4);\n\n  &:hover {\n    color: rgba(255, 255, 255, 0.7);\n  }\n}\n"],"sourceRoot":""}]);
