A,yCAAA","sourcesContent":["\n.imap-overlay {\n  position: absolute;\n  inset: 0;\n  background: rgba(0, 0, 0, 0.6);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  z-index: 100;\n  backdrop-filter: blur(2px);\n}\n\n.imap-popup {\n  background: #222228;\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  border-radius: 12px;\n  width: min(380px, 88vw);\n  max-height: 70vh;\n  display: flex;\n  flex-direction: column;\n  overflow: hidden;\n  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.5);\n  animation: popupIn 0.2s ease-out;\n}\n\n@keyframes popupIn {\n  from {\n    opacity: 0;\n    transform: scale(0.95) translateY(8px);\n  }\n\n  to {\n    opacity: 1;\n    transform: scale(1) translateY(0);\n  }\n}\n\n.imap-popup-header {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 14px 16px;\n  border-bottom: 1px solid rgba(255, 255, 255, 0.06);\n\n  h3 {\n    flex: 1;\n    margin: 0;\n    font-size: 16px;\n    color: #fff;\n    font-weight: 600;\n    display: flex;\n    align-items: center;\n    gap: 8px;\n  }\n}\n\n.imap-popup-color {\n  width: 4px;\n  height: 24px;\n  border-radius: 2px;\n  flex-shrink: 0;\n}\n\n.imap-popup-close {\n  background: none;\n  border: none;\n  color: rgba(255, 255, 255, 0.4);\n  font-size: 16px;\n  cursor: pointer;\n  padding: 4px;\n  border-radius: 50%;\n  transition: all 0.2s;\n  flex-shrink: 0;\n\n  &:hover {\n    color: #fff;\n    background: rgba(255, 255, 255, 0.1);\n  }\n}\n\n.imap-popup-back {\n  background: none;\n  border: none;\n  color: rgba(255, 255, 255, 0.5);\n  font-size: 16px;\n  cursor: pointer;\n  padding: 2px 4px;\n\n  &:hover {\n    color: #fff;\n  }\n}\n\n.imap-popup-body {\n  padding: 14px 16px;\n  overflow-y: auto;\n  flex: 1;\n}\n\n.imap-popup-desc {\n  color: rgba(255, 255, 255, 0.65);\n  font-size: 14px;\n  line-height: 1.6;\n  margin: 0 0 12px;\n}\n\n.imap-floors {\n  h4 {\n    font-size: 13px;\n    color: rgba(255, 255, 255, 0.4);\n    margin: 0 0 8px;\n    font-weight: 500;\n    text-transform: uppercase;\n    letter-spacing: 0.5px;\n  }\n}\n\n.imap-floor-item {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 8px 10px;\n  border-radius: 6px;\n  cursor: pointer;\n  transition: background 0.15s;\n  margin-bottom: 2px;\n\n  &:hover {\n    background: rgba(255, 255, 255, 0.06);\n  }\n}\n\n.imap-floor-name {\n  font-size: 13px;\n  color: rgba(255, 255, 255, 0.8);\n}\n\n.imap-floor-arrow {\n  color: rgba(255, 255, 255, 0.25);\n  font-size: 16px;\n}\n\n.imap-popup-actions {\n  padding: 12px 16px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n  display: flex;\n  justify-content: center;\n  gap: 8px;\n}\n\n.imap-btn {\n  padding: 8px 20px;\n  border-radius: 8px;\n  font-size: 14px;\n  cursor: pointer;\n  transition: all 0.2s;\n  border: none;\n}\n\n.imap-btn-primary {\n  background: linear-gradient(135deg, #b38b59, #9a7548);\n  color: #fff;\n  font-weight: 500;\n\n  &:hover {\n    background: linear-gradient(135deg, #c99e68, #b38b59);\n    transform: translateY(-1px);\n    box-shadow: 0 4px 12px rgba(179, 139, 89, 0.3);\n  }\n}\n"],"sourceRoot":""}]);
